// ─── Types ────────────────────────────────────────────────────────────────────

export interface OrderItem {
  id: number;
  name: string;
  category?: string;
  price: number;
  qty: number;
  subtotal: number;
}

export interface TimelineEvent {
  status: string;
  timestamp: string;
  by?: string; // staff name
  note?: string;
}

export interface Order {
  id: string;
  orderNum?: number;           // Sequential human-readable number (#1001, #1002 …)
  type: 'dine-in' | 'pickup';
  tableId?: number;
  customerName: string;
  phone?: string;
  items: OrderItem[];
  subtotal: number;
  discount: number;
  discountReason?: string;
  total: number;
  payment: string;
  status: 'awaiting_waiter' | 'pending' | 'preparing' | 'prepared' | 'served' | 'completed' | 'void' | 'cancelled';
  cancelReason?: string;
  cancelledAt?: string;
  voidReason?: string;         // Void = food already prepared, transaction reversed
  voidedAt?: string;
  staffName?: string;
  partySize?: number;          // How many people are in this customer's group
  timeline: TimelineEvent[];
  editHistory?: { timestamp: string; change: string; by?: string }[];
  timestamp: string;
  tableOpenedAt?: string;
}

export interface Table {
  id: number;
  chairs: number;
  status: 'available' | 'occupied' | 'reserved';
  occupants: { name: string }[];
  sessionStart?: string;
}

export interface MenuItem {
  id: number;
  category: string;
  name: string;
  desc: string;
  price: number;
  img?: string;
  badge?: string;
  available?: boolean;
}

export interface StaffSession {
  id: string;
  name: string;
  role: string;
  loginAt: string;
  logoutAt?: string;
}

export interface WaiterCall {
  id: string;
  tableId: number;
  customerName?: string;
  message: string;
  timestamp: string;
  resolved: boolean;
  resolvedAt?: string;
  resolvedBy?: string;
}

export interface CustomerTab {
  id:              string;
  tableId:         number;
  customerName:    string;
  partySize?:      number;
  tabStatus:       'open' | 'awaiting_payment' | 'closed';
  orderIds:        string[];   // orders placed within this tab
  totalAmount:     number;     // aggregated total (recalculated from orders minus discount)
  discount?:       number;
  discountReason?: string;
  payment?:        string;     // payment method used at close
  createdAt:       string;
  requestedAt?:    string;     // when customer hit "Request Bill"
  closedAt?:       string;     // when manager closed the tab
}

// ─── Keys ─────────────────────────────────────────────────────────────────────
const KEYS = {
  orders:       'fl_orders',
  tables:       'fl_tables',
  menu:         'fl_menu',
  pin:          'fl_owner_pin',
  staff:        'fl_staff_sessions',
  calls:        'fl_waiter_calls',
  priority:     'fl_priority_orders',
  orderCounter: 'fl_order_counter',   // sequential order number
  tabs:         'fl_tabs',
};

// ─── Helpers ──────────────────────────────────────────────────────────────────
function get<T>(key: string, fallback: T): T {
  if (typeof window === 'undefined') return fallback;
  try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : fallback; }
  catch { return fallback; }
}
function set<T>(key: string, value: T): void {
  if (typeof window === 'undefined') return;
  localStorage.setItem(key, JSON.stringify(value));
}

// ─── Order Lifecycle Safety ────────────────────────────────────────────────────
//
//  Allowed transitions — enforced in updateOrderStatus().
//  Use force=true (admin only) to bypass when truly needed.
//
export const VALID_TRANSITIONS: Readonly<Record<Order['status'], readonly Order['status'][]>> = {
  awaiting_waiter: ['pending', 'cancelled'],   // waiter confirms → pending, or cancels with reason
  pending:         ['preparing', 'cancelled'],
  preparing:       ['prepared',  'cancelled'],
  prepared:        ['served', 'void'],          // void = food made but transaction reversed
  served:          ['completed', 'void'],       // void after delivery — rare fraud-prevention case
  completed:       [],
  void:            [],
  cancelled:       [],
} as const;

export function isValidTransition(
  from: Order['status'],
  to:   Order['status'],
): boolean {
  const allowed = VALID_TRANSITIONS[from];
  return allowed ? (allowed as readonly string[]).includes(to) : false;
}

// ─── Orders ───────────────────────────────────────────────────────────────────
export const getOrders  = (): Order[]        => get<Order[]>(KEYS.orders, []);
export const saveOrders = (o: Order[])       => set(KEYS.orders, o);

/** Returns the next sequential order number (starting at 1001). Thread-safe via localStorage. */
export function getNextOrderNumber(): number {
  const current = get<number>(KEYS.orderCounter, 1000);
  const next = current + 1;
  set(KEYS.orderCounter, next);
  return next;
}

export function addOrder(order: Order) {
  const orders = getOrders();

  // Guard: block duplicate IDs (rapid double-submit protection)
  if (orders.some(o => o.id === order.id)) return;

  // Auto-assign a sequential human-readable order number if not already set
  if (!order.orderNum) {
    order.orderNum = getNextOrderNumber();
  }

  // Ensure timeline is always initialised (use the order's actual starting status)
  if (!order.timeline || !order.timeline.length) {
    order.timeline = [{ status: order.status, timestamp: order.timestamp }];
  }
  orders.push(order);
  saveOrders(orders);

  // Auto-mark table as occupied when a dine-in order is placed
  if (order.type === 'dine-in' && order.tableId) {
    syncTableStatus(order.tableId);
  }
}

/**
 * Update an order's status.
 * Returns `true` on success, `false` if the transition is invalid.
 * Pass `force = true` (admin only) to skip the transition guard.
 */
export function updateOrderStatus(
  orderId: string,
  status:  Order['status'],
  by?:     string,
  force =  false,
): boolean {
  const orders = getOrders();
  const idx = orders.findIndex(o => o.id === orderId);
  if (idx === -1) return false;

  const current = orders[idx].status;

  // Prevent any changes on already-cancelled or completed orders unless forced
  if (!force && !isValidTransition(current, status)) return false;

  orders[idx].status = status;
  if (!orders[idx].timeline) orders[idx].timeline = [];
  orders[idx].timeline.push({ status, timestamp: new Date().toISOString(), by });
  saveOrders(orders);

  // Sync table status when a dine-in order completes or is served
  if (orders[idx].type === 'dine-in' && orders[idx].tableId) {
    syncTableStatus(orders[idx].tableId!);
  }
  return true;
}

export function cancelOrder(orderId: string, reason: string, by?: string): boolean {
  const orders = getOrders();
  const idx = orders.findIndex(o => o.id === orderId);
  if (idx === -1) return false;

  // Allow cancellation from: unconfirmed, pending, or being prepared
  const cancellable: Order['status'][] = ['awaiting_waiter', 'pending', 'preparing'];
  if (!cancellable.includes(orders[idx].status)) return false;

  orders[idx].status = 'cancelled';
  orders[idx].cancelReason = reason;
  orders[idx].cancelledAt = new Date().toISOString();
  if (!orders[idx].timeline) orders[idx].timeline = [];
  orders[idx].timeline.push({
    status: 'cancelled',
    timestamp: new Date().toISOString(),
    by,
    note: reason,
  });
  saveOrders(orders);

  // Free up the table if no other active orders remain for it
  if (orders[idx].type === 'dine-in' && orders[idx].tableId) {
    syncTableStatus(orders[idx].tableId!);
  }
  return true;
}

/**
 * Void an order (food already prepared/served but transaction is reversed).
 * Different from cancellation — void requires admin-level justification.
 * Void is only allowed from 'prepared' or 'served' states.
 */
export function voidOrder(orderId: string, reason: string, by?: string): boolean {
  const orders = getOrders();
  const idx = orders.findIndex(o => o.id === orderId);
  if (idx === -1) return false;

  const voidable: Order['status'][] = ['prepared', 'served'];
  if (!voidable.includes(orders[idx].status)) return false;

  orders[idx].status    = 'void';
  orders[idx].voidReason = reason;
  orders[idx].voidedAt  = new Date().toISOString();
  if (!orders[idx].timeline) orders[idx].timeline = [];
  orders[idx].timeline.push({
    status:    'void',
    timestamp: new Date().toISOString(),
    by,
    note: `VOID — ${reason}`,
  });
  saveOrders(orders);

  // Free table if no other active orders remain
  if (orders[idx].type === 'dine-in' && orders[idx].tableId) {
    syncTableStatus(orders[idx].tableId!);
  }
  return true;
}

/**
 * Append new items to an existing open order (the "Order More" flow).
 * - Same item ID → quantity merged and subtotal recalculated
 * - New item ID → added to the list
 * - If the order was already `prepared` or `served` (kitchen already done), it is
 *   reset to `preparing` so the kitchen gets a new pass for the extra items.
 * - Terminal statuses (completed / void / cancelled) are rejected.
 */
export function addItemsToOrder(
  orderId:  string,
  newItems: OrderItem[],
  by?:      string,
): boolean {
  const orders = getOrders();
  const idx = orders.findIndex(o => o.id === orderId);
  if (idx === -1) return false;

  const terminal: Order['status'][] = ['completed', 'void', 'cancelled'];
  if (terminal.includes(orders[idx].status)) return false;

  // Merge items — bump qty for existing, push for new
  newItems.forEach(newItem => {
    const ei = orders[idx].items.findIndex(i => i.id === newItem.id);
    if (ei >= 0) {
      orders[idx].items[ei].qty     += newItem.qty;
      orders[idx].items[ei].subtotal = orders[idx].items[ei].price * orders[idx].items[ei].qty;
    } else {
      orders[idx].items.push({ ...newItem });
    }
  });

  // Recalculate order totals
  const subtotal = orders[idx].items.reduce((s, i) => s + i.subtotal, 0);
  orders[idx].subtotal = subtotal;
  orders[idx].total    = subtotal - (orders[idx].discount || 0);

  // Record edit history
  if (!orders[idx].editHistory) orders[idx].editHistory = [];
  const addedSummary = newItems.map(i => `${i.name} ×${i.qty}`).join(', ');
  orders[idx].editHistory!.push({
    timestamp: new Date().toISOString(),
    change: `Added items: ${addedSummary}`,
    by,
  });

  // If already prepared/served, return to kitchen for the new items
  const needsKitchen: Order['status'][] = ['prepared', 'served'];
  if (needsKitchen.includes(orders[idx].status)) {
    orders[idx].status = 'preparing';
    orders[idx].timeline.push({
      status:    'preparing',
      timestamp: new Date().toISOString(),
      by,
      note: `🆕 Extra items ordered — back to kitchen: ${addedSummary}`,
    });
  } else {
    orders[idx].timeline.push({
      status:    orders[idx].status,
      timestamp: new Date().toISOString(),
      by,
      note: `🆕 Items added: ${addedSummary}`,
    });
  }

  saveOrders(orders);

  // Keep table occupied
  if (orders[idx].type === 'dine-in' && orders[idx].tableId) {
    syncTableStatus(orders[idx].tableId!);
  }
  return true;
}

export function applyDiscount(
  orderId:  string,
  discount: number,
  reason:   string,
  by?:      string,
): boolean {
  const orders = getOrders();
  const idx = orders.findIndex(o => o.id === orderId);
  if (idx === -1) return false;

  const sub = orders[idx].subtotal || orders[idx].total;

  // Clamp discount to [0, subtotal] — prevents negative totals
  const safeDiscount = Math.min(Math.max(0, Math.round(discount)), sub);

  orders[idx].discount = safeDiscount;
  orders[idx].discountReason = reason;
  orders[idx].total = sub - safeDiscount;

  if (!orders[idx].editHistory) orders[idx].editHistory = [];
  orders[idx].editHistory!.push({
    timestamp: new Date().toISOString(),
    change: `Discount ₹${safeDiscount} applied: ${reason}`,
    by,
  });
  saveOrders(orders);
  return true;
}

// ─── Priority Orders (persistent across refresh) ─────────────────────────────
export const getPriorityOrders  = (): Record<string, boolean> =>
  get<Record<string, boolean>>(KEYS.priority, {});

export function savePriorityOrders(map: Record<string, boolean>): void {
  // Prune completed/cancelled orders from the priority map
  const orders = getOrders();
  const activeIds = new Set(
    orders
      .filter(o => ['awaiting_waiter', 'pending', 'preparing', 'prepared'].includes(o.status))
      .map(o => o.id),
  );
  // Note: void/cancelled/completed are intentionally excluded from priority tracking
  const pruned: Record<string, boolean> = {};
  for (const [id, val] of Object.entries(map)) {
    if (activeIds.has(id) && val) pruned[id] = true;
  }
  set(KEYS.priority, pruned);
}

// ─── Tables ───────────────────────────────────────────────────────────────────
export function getTables(): Table[] {
  const saved = get<Table[] | null>(KEYS.tables, null);
  if (saved) return saved;
  const defaults: Table[] = Array.from({ length: 15 }, (_, i) => ({
    id: i + 1, chairs: 4, status: 'available', occupants: [],
  }));
  set(KEYS.tables, defaults);
  return defaults;
}
export const saveTables = (t: Table[]) => set(KEYS.tables, t);

/**
 * Auto-sync a table's status based on whether any active tabs or legacy orders exist.
 * A table is occupied if it has any open or awaiting_payment tabs, or legacy orders.
 * Should be called after any order or tab state change.
 */
export function syncTableStatus(tableId: number): void {
  const tables = getTables();
  const idx = tables.findIndex(t => t.id === tableId);
  if (idx === -1) return;

  // A table is occupied if it has any open or awaiting_payment tabs
  const activeTabs = getTabs().filter(
    t => t.tableId === tableId && ['open', 'awaiting_payment'].includes(t.tabStatus),
  );
  // Also check legacy orders not linked to tabs (backward compat)
  const orders = getOrders();
  const activeOrders = orders.filter(
    o => o.tableId === tableId &&
    ['awaiting_waiter', 'pending', 'preparing', 'prepared', 'served'].includes(o.status),
  );
  const occupied = activeTabs.length > 0 || activeOrders.length > 0;

  if (tables[idx].status !== 'reserved') {
    tables[idx].status = occupied ? 'occupied' : 'available';
    if (occupied) {
      tables[idx].occupants = activeTabs.map(t => ({ name: t.customerName }));
      if (!tables[idx].sessionStart) tables[idx].sessionStart = new Date().toISOString();
    } else {
      tables[idx].occupants    = [];
      tables[idx].sessionStart = undefined;
    }
  }
  saveTables(tables);
}

/** Per-table occupancy snapshot used by Manager / Admin dashboards */
export interface TableOccupancy {
  tableId:        number;
  tableName:      string;
  capacity:       number;   // chairs at this table
  chairsOccupied: number;   // sum of partySize for all active orders
  partiesCount:   number;   // distinct customer groups
  guests:         { name: string; partySize: number; status: string; orderTotal: number }[];
  tableStatus:    'available' | 'occupied' | 'reserved';
  sessionStart?:  string;
}

export function getTableOccupancy(): TableOccupancy[] {
  const tables = getTables();
  const tabs   = getTabs();
  const orders = getOrders();
  const ACTIVE_TAB: CustomerTab['tabStatus'][] = ['open', 'awaiting_payment'];

  return tables.map(t => {
    const activeTabs = tabs.filter(tb => tb.tableId === t.id && ACTIVE_TAB.includes(tb.tabStatus));
    const chairsOccupied = activeTabs.reduce((s, tb) => s + (tb.partySize ?? 1), 0);
    const guests = activeTabs.map(tb => {
      const tabOrders = orders.filter(o => tb.orderIds.includes(o.id) && !['void','cancelled'].includes(o.status));
      return {
        name:       tb.customerName,
        partySize:  tb.partySize ?? 1,
        status:     tb.tabStatus,
        orderTotal: tb.totalAmount,
      };
    });
    return {
      tableId:        t.id,
      tableName:      `Table ${t.id}`,
      capacity:       t.chairs,
      chairsOccupied,
      partiesCount:   activeTabs.length,
      guests,
      tableStatus:    t.status,
      sessionStart:   t.sessionStart,
    };
  });
}

