export const getWaiterCalls  = (): WaiterCall[] => get(KEYS.calls, []);
export const saveWaiterCalls = (c: WaiterCall[]) => set(KEYS.calls, c);

export function addWaiterCall(tableId: number, message: string, customerName?: string): void {
  const calls = getWaiterCalls();
  calls.push({
    id: `CALL-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
    tableId, customerName, message,
    timestamp: new Date().toISOString(),
    resolved: false,
  });
  saveWaiterCalls(calls);
}

export function resolveWaiterCall(callId: string, by?: string): void {
  const calls = getWaiterCalls();
  const idx = calls.findIndex(c => c.id === callId);
  if (idx === -1) return;
  calls[idx].resolved   = true;
  calls[idx].resolvedAt = new Date().toISOString();
  calls[idx].resolvedBy = by;
  saveWaiterCalls(calls);
}

// ─── Analytics helpers ────────────────────────────────────────────────────────
export function getOrdersInPeriod(period: 'today'|'week'|'month'|'all'): Order[] {
  const all = getOrders();
  const now = new Date();
  return all.filter(o => {
    // Exclude cancelled, voided, and unconfirmed orders from revenue/analytics
    if (o.status === 'cancelled' || o.status === 'void' || o.status === 'awaiting_waiter') return false;
    const d = new Date(o.timestamp);
    if (period === 'today') return d.toDateString() === now.toDateString();
    if (period === 'week')  { const s=new Date(now); s.setDate(now.getDate()-now.getDay()); s.setHours(0,0,0,0); return d>=s; }
    if (period === 'month') return d.getFullYear()===now.getFullYear()&&d.getMonth()===now.getMonth();
    return true;
  });
}

// ─── CSV Export ───────────────────────────────────────────────────────────────
export function exportOrdersCSV() {
  const orders = getOrders();
  if (!orders.length) { alert('No orders to export.'); return; }

  const DAY   = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const MONTH = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const PAY:Record<string,string> = { paytm:'Paytm', phonepe:'PhonePe', gpay:'Google Pay', cod:'Cash' };

  const headers = ['Order ID','Date','Time','Day','Week No.','Month','Year','Customer','Phone','Type','Table/Pickup','Staff','Item Name','Item Qty','Unit Price (₹)','Line Total (₹)','Subtotal (₹)','Discount (₹)','Discount Reason','Total (₹)','Payment','Status','Cancel Reason'];
  const rows: (string|number)[][] = [];

  orders.forEach(order => {
    const d    = new Date(order.timestamp);
    const date = `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;
    const time = d.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'});
    const loc  = order.type==='dine-in'?`Table ${order.tableId}`:'Pickup';
    const pay  = PAY[order.payment]??order.payment??'';
    const items= order.items??[];

    if (!items.length) {
      rows.push([order.id,date,time,DAY[d.getDay()],Math.ceil(d.getDate()/7),MONTH[d.getMonth()],d.getFullYear(),order.customerName,order.phone??'',order.type,loc,order.staffName??'','','','','',order.subtotal,order.discount??0,order.discountReason??'',order.total,pay,order.status,order.cancelReason??'']);
    } else {
      items.forEach((item,i)=>{
        const line=item.subtotal??(item.price*item.qty);
        rows.push([i===0?order.id:'',i===0?date:'',i===0?time:'',i===0?DAY[d.getDay()]:'',i===0?Math.ceil(d.getDate()/7):'',i===0?MONTH[d.getMonth()]:'',i===0?d.getFullYear():'',i===0?order.customerName:'',i===0?(order.phone??''):'',i===0?order.type:'',i===0?loc:'',i===0?(order.staffName??''):'',item.name,item.qty,item.price,line,i===0?order.subtotal:'',i===0?(order.discount??0):'',i===0?(order.discountReason??''):'',i===0?order.total:'',i===0?pay:'',i===0?order.status:'',i===0?(order.cancelReason??''):'']);
      });
    }
  });

  const esc=(v:string|number)=>{const s=String(v??'');return(s.includes(',')||s.includes('"')||s.includes('\n'))?`"${s.replace(/"/g,'""')}"`:s;};
  const csv=[headers,...rows].map(r=>r.map(esc).join(',')).join('\n');
  const blob=new Blob(['\uFEFF'+csv],{type:'text/csv;charset=utf-8;'});
  const url=URL.createObjectURL(blob);
  const now=new Date();
  const fname=`FoodieLover_${now.getFullYear()}${String(now.getMonth()+1).padStart(2,'0')}${String(now.getDate()).padStart(2,'0')}.csv`;
  const a=document.createElement('a');a.href=url;a.download=fname;
  document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url);
}

// ─── End-of-Day Report ────────────────────────────────────────────────────────

export interface EndOfDayReport {
  date: string;
  totalOrders: number;
  completedOrders: number;
  cancelledOrders: number;
  voidedOrders: number;
  awaitingOrders: number;
  grossRevenue: number;
  discounts: number;
  netRevenue: number;
  paymentBreakdown: Record<string, { count: number; amount: number }>;
  avgBillValue: number;
  peakHour: string;
  topItems: { name: string; qty: number }[];
}

export function getEndOfDayReport(date?: Date): EndOfDayReport {
  const d = date || new Date();
  const dayStr = d.toDateString();
  const all = getOrders().filter(o => new Date(o.timestamp).toDateString() === dayStr);

  const completed = all.filter(o => o.status === 'completed');
  const cancelled = all.filter(o => o.status === 'cancelled');
  const voided    = all.filter(o => o.status === 'void');
  const awaiting  = all.filter(o => o.status === 'awaiting_waiter');

  const gross = completed.reduce((s, o) => s + (o.subtotal || o.total), 0);
  const disc  = completed.reduce((s, o) => s + (o.discount || 0), 0);
  const net   = completed.reduce((s, o) => s + o.total, 0);

  // Payment breakdown
  const payBreak: Record<string, { count: number; amount: number }> = {};
  completed.forEach(o => {
    const pay = o.payment || 'cod';
    if (!payBreak[pay]) payBreak[pay] = { count: 0, amount: 0 };
    payBreak[pay].count++;
    payBreak[pay].amount += o.total;
  });

  // Peak hour (by order count)
  const hourCounts: Record<number, number> = {};
  all.forEach(o => {
    const h = new Date(o.timestamp).getHours();
    hourCounts[h] = (hourCounts[h] || 0) + 1;
  });
  const peakEntry = Object.entries(hourCounts).sort((a, b) => Number(b[1]) - Number(a[1]))[0];
  const peakHour  = peakEntry
    ? `${String(Number(peakEntry[0])).padStart(2, '0')}:00 – ${String(Number(peakEntry[0])).padStart(2, '0')}:59`
    : 'N/A';

  // Top items (from completed orders only)
  const itemMap: Record<string, number> = {};
  completed.forEach(o => {
    o.items.forEach(item => {
      itemMap[item.name] = (itemMap[item.name] || 0) + item.qty;
    });
  });
  const topItems = Object.entries(itemMap)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 6)
    .map(([name, qty]) => ({ name, qty }));

  return {
    date: d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }),
    totalOrders:      all.length,
    completedOrders:  completed.length,
    cancelledOrders:  cancelled.length,
    voidedOrders:     voided.length,
    awaitingOrders:   awaiting.length,
    grossRevenue:     gross,
    discounts:        disc,
    netRevenue:       net,
    paymentBreakdown: payBreak,
    avgBillValue:     completed.length ? Math.round(net / completed.length) : 0,
    peakHour,
    topItems,
  };
}

// ─── Fraud Alerts ─────────────────────────────────────────────────────────────

export interface FraudAlert {
  type: 'high_cancellations' | 'high_discounts' | 'voided_orders' | 'large_single_discount';
  severity: 'warning' | 'critical';
  message: string;
  staff?: string;
  count?: number;
  details?: string;
}

export function getFraudAlerts(): FraudAlert[] {
  const today  = new Date().toDateString();
  const orders = getOrders().filter(o => new Date(o.timestamp).toDateString() === today);
  const alerts: FraudAlert[] = [];

  // Waiter/staff with many cancellations today
  const cancelByStaff: Record<string, number> = {};
  orders.filter(o => o.status === 'cancelled').forEach(o => {
    const who = o.staffName || 'Unknown';
    cancelByStaff[who] = (cancelByStaff[who] || 0) + 1;
  });
  Object.entries(cancelByStaff).forEach(([staff, count]) => {
    if (count >= 3) {
      alerts.push({
        type: 'high_cancellations',
        severity: count >= 5 ? 'critical' : 'warning',
        message: `${staff} has ${count} cancellation${count > 1 ? 's' : ''} today`,
        staff,
        count,
      });
    }
  });

  // High number of discounts today
  const discountOrders = orders.filter(o => (o.discount || 0) > 0);
  if (discountOrders.length >= 5) {
    const totalDisc = discountOrders.reduce((s, o) => s + (o.discount || 0), 0);
    alerts.push({
      type: 'high_discounts',
      severity: discountOrders.length >= 10 ? 'critical' : 'warning',
      message: `${discountOrders.length} discounts today totalling ₹${totalDisc}`,
      count: discountOrders.length,
    });
  }

  // Large individual discounts (>₹100)
  orders.filter(o => (o.discount || 0) > 100).forEach(o => {
    alerts.push({
      type: 'large_single_discount',
      severity: 'warning',
      message: `Large discount ₹${o.discount} on order ${o.orderNum ? `#${o.orderNum}` : o.id}`,
      details: o.discountReason || 'No reason given',
    });
  });

  // Any voided orders today
  const voidOrders = orders.filter(o => o.status === 'void');
  if (voidOrders.length > 0) {
    alerts.push({
      type: 'voided_orders',
      severity: voidOrders.length >= 2 ? 'critical' : 'warning',
      message: `${voidOrders.length} order${voidOrders.length > 1 ? 's' : ''} voided today — verify with manager`,
      count: voidOrders.length,
    });
  }

  return alerts;
}
